    48→// Draggable navigation items (user can reorganize)
    49→// Structure per Option A from sidebar-navigation-review.md:
    50→// - Parent becomes Tab 1, children become subsequent tabs left-to-right
    51→// - Schedule: Calendar (parent), Timer, Pomodoro (simplified from 10 tabs)
    52→// - Notes: Notes (parent), Daily Notes, Graph (Diagrams/Forms moved to Create)
    53→// - Tasks: Tasks (parent), Timeline, Habits (moved here from standalone)
    54→// - Create: All (parent), Documents, Spreadsheets, Presentations, Diagrams, Forms
    55→const draggableNavigation: NavItem[] = [
    56→  {
