   108→
   109→// Sortable Navigation Item Component
   110→interface SortableNavItemProps {
   111→  item: NavItem;
   112→  isCollapsed: boolean;
   113→  isActive: boolean;
   114→  onPageSettings: (e: React.MouseEvent, path: string) => void;
   115→  isDisablingClicks: boolean;
   116→}
   117→
   118→const SortableNavItem: React.FC<SortableNavItemProps> = ({ item, isCollapsed, isActive, onPageSettings, isDisablingClicks }) => {
   119→  const {
   120→    attributes,
   121→    listeners,
   122→    setNodeRef,
   123→    transform,
   124→    transition,
   125→    isDragging,
   126→  } = useSortable({ id: item.path });
   127→
   128→  const location = useLocation();
   129→  const { isExpanded, toggleExpanded } = useNavExpansionStore();
   130→  const hasChildren = item.children && item.children.length > 0;
   131→  const expanded = isExpanded(item.path);
   132→
   133→  const style = {
   134→    transform: CSS.Transform.toString(transform),
   135→    transition,
   136→    opacity: isDragging ? 0.5 : 1,
   137→  };
   138→
   139→  // Check if any child is active
   140→  const isChildActive = (navItem: NavItem) => {
   141→    if (!navItem.children) return false;
   142→    return navItem.children.some((child) => {
   143→      // Handle paths with query params
   144→      if (child.path.includes('?')) {
   145→        const [pathname, query] = child.path.split('?');
   146→        if (location.pathname !== pathname) return false;
   147→        const params = new URLSearchParams(query);
   148→        const currentParams = new URLSearchParams(location.search);
   149→        for (const [key, value] of params.entries()) {
   150→          if (currentParams.get(key) !== value) return false;
   151→        }
   152→        return true;
   153→      }
   154→      return location.pathname === child.path;
   155→    });
