   353→  // Sort draggable navigation items by saved order
   354→  const sortedDraggableNavigation = [...draggableNavigation].sort((a, b) => {
   355→    const aIndex = navOrder.indexOf(a.path);
   356→    const bIndex = navOrder.indexOf(b.path);
