/**
 * FolderTreeNode Component
 *
 * Recursive folder tree node for the Notes sidebar.
 * Extracted from Notes.tsx as part of the Notes Page Revolution.
 *
 * Features:
 * - Recursive rendering for nested folders
 * - Expand/collapse with chevron icons
 * - Note count display
 * - Hover actions (rename, delete)
 * - Active state highlighting with left accent bar
 */

import React, { useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  ChevronDown,
  ChevronRight,
  FolderOpen,
  Folder,
  FileText,
  Edit2,
  Trash2,
} from 'lucide-react';
import { useReducedMotion } from '../../hooks/useReducedMotion';

// Animation variants for folder children (with reduced motion support)
const getChildrenVariants = (reduceMotion: boolean) => ({
  hidden: {
    opacity: reduceMotion ? 1 : 0,
    height: 0,
    transition: { duration: reduceMotion ? 0 : 0.15, ease: 'easeInOut' as const }
  },
  visible: {
    opacity: 1,
    height: 'auto',
    transition: { duration: reduceMotion ? 0 : 0.15, ease: 'easeInOut' as const }
  },
});

export interface FolderNode {
  id: string;
  name: string;
  children?: FolderNode[];
}

export interface FolderTreeNodeProps {
  node: FolderNode;
  depth: number;
  activeFolderId: string | null;
  expandedFolderIds: Set<string>;
  onSelect: (id: string) => void;
  onToggleExpanded: (id: string) => void;
  onDelete: (id: string, name: string) => void;
  onRename: (id: string, name: string) => void;
  getFolderNoteCount: (id: string) => number;
}

export const FolderTreeNode: React.FC<FolderTreeNodeProps> = ({
  node,
  depth,
  activeFolderId,
  expandedFolderIds,
  onSelect,
  onToggleExpanded,
  onDelete,
  onRename,
  getFolderNoteCount,
}) => {
  const isExpanded = expandedFolderIds.has(node.id);
  const hasChildren = node.children && node.children.length > 0;
  const noteCount = getFolderNoteCount(node.id);
  const isActive = activeFolderId === node.id;

  // Reduced motion support
  const prefersReducedMotion = useReducedMotion();
  const childrenVariants = useMemo(
    () => getChildrenVariants(prefersReducedMotion),
    [prefersReducedMotion]
  );

  return (
    <div role="treeitem" aria-expanded={hasChildren ? isExpanded : undefined} aria-selected={isActive}>
      <div
        className={`group relative rounded-lg transition-all duration-150 h-10 flex items-center ${
          isActive
            ? 'bg-transparent border-l-2 border-accent-cyan dark:border-accent-magenta pl-[14px]'
            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated border-l-2 border-transparent pl-[14px]'
        }`}
        style={{ paddingLeft: `${depth * 16 + 14}px` }}
      >
        <div className="flex items-center flex-1 min-w-0">
          {/* Expand/collapse button */}
          {hasChildren ? (
            <button
              onClick={(e) => {
                e.stopPropagation();
                onToggleExpanded(node.id);
              }}
              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors flex-shrink-0"
              aria-label={isExpanded ? 'Collapse folder' : 'Expand folder'}
            >
              {isExpanded ? (
                <ChevronDown className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
              ) : (
                <ChevronRight className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
              )}
            </button>
          ) : (
            <span className="w-6 flex-shrink-0" />
          )}

          {/* Folder button */}
          <button
            onClick={() => onSelect(node.id)}
            className={`flex-1 text-left px-2 py-1.5 transition-all duration-150 flex items-center gap-2 min-w-0 ${
              isActive
                ? 'text-accent-cyan dark:text-accent-magenta font-medium'
                : 'text-text-light-secondary dark:text-text-dark-secondary group-hover:text-text-light-primary dark:group-hover:text-text-dark-primary'
            }`}
          >
            {hasChildren ? (
              isExpanded ? (
                <FolderOpen className="w-4 h-4 flex-shrink-0" />
              ) : (
                <Folder className="w-4 h-4 flex-shrink-0" />
              )
            ) : (
              <FileText className="w-4 h-4 flex-shrink-0" />
            )}
            <span className="text-sm font-medium truncate">{node.name}</span>
            {noteCount > 0 && (
              <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary flex-shrink-0">
                ({noteCount})
              </span>
            )}
          </button>

          {/* Action buttons - progressive disclosure */}
          <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex gap-1 transition-opacity duration-100">
            <button
              onClick={(e) => {
                e.stopPropagation();
                onRename(node.id, node.name);
              }}
              className="p-1.5 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
              title="Rename folder"
              aria-label="Rename folder"
            >
              <Edit2 className="w-3.5 h-3.5 text-text-light-secondary dark:text-text-dark-secondary" />
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onDelete(node.id, node.name);
              }}
              className="p-1.5 hover:bg-accent-red/10 dark:hover:bg-accent-red/20 rounded text-accent-red transition-colors"
              title="Delete folder"
              aria-label="Delete folder"
            >
              <Trash2 className="w-3.5 h-3.5" />
            </button>
          </div>
        </div>
      </div>

      {/* Children - animated expand/collapse */}
      <AnimatePresence initial={false}>
        {isExpanded && hasChildren && (
          <motion.div
            role="group"
            className="ml-4 overflow-hidden"
            initial="hidden"
            animate="visible"
            exit="hidden"
            variants={childrenVariants}
          >
            {node.children!.map((child) => (
              <FolderTreeNode
                key={child.id}
                node={child}
                depth={depth + 1}
                activeFolderId={activeFolderId}
                expandedFolderIds={expandedFolderIds}
                onSelect={onSelect}
                onToggleExpanded={onToggleExpanded}
                onDelete={onDelete}
                onRename={onRename}
                getFolderNoteCount={getFolderNoteCount}
              />
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

