     1→/**
     2→ * ProjectContextDropdown Component
     3→ *
     4→ * Global project context switcher for the page header.
     5→ * Allows users to filter all content to a specific project or view all.
     6→ *
     7→ * Features:
     8→ * - Dropdown with hierarchical project tree
     9→ * - "All Projects" option at top
    10→ * - Current selection display with project color
    11→ * - Keyboard navigation support
    12→ * - Click outside to close
    13→ */
    14→
    15→import React, { useRef, useEffect, useCallback, useState } from 'react';
    16→import { ChevronDown, Globe, Settings } from 'lucide-react';
    17→import { useProjectContextStore } from '../stores/useProjectContextStore';
    18→import { ProjectTree } from './ProjectTree';
    19→import { ProjectSettingsModal } from './ProjectSettingsModal';
    20→
    21→interface ProjectContextDropdownProps {
    22→  /** Custom class for the container */
    23→  className?: string;
    24→}
    25→
    26→export const ProjectContextDropdown: React.FC<ProjectContextDropdownProps> = ({
    27→  className = '',
    28→}) => {
    29→  const dropdownRef = useRef<HTMLDivElement>(null);
    30→  const buttonRef = useRef<HTMLButtonElement>(null);
    31→  const [showSettingsModal, setShowSettingsModal] = useState(false);
    32→
    33→  // Store state - use global isDropdownOpen for keyboard shortcut support
    34→  const isOpen = useProjectContextStore((s) => s.isDropdownOpen);
    35→  const setIsOpen = useProjectContextStore((s) => s.setDropdownOpen);
    36→  const activeProjectIds = useProjectContextStore((s) => s.activeProjectIds);
    37→  const setActiveProjects = useProjectContextStore((s) => s.setActiveProjects);
    38→  const projects = useProjectContextStore((s) => s.projects);
    39→  const getProjectPath = useProjectContextStore((s) => s.getProjectPath);
    40→
    41→  // Determine display state
    42→  const isAllSelected = activeProjectIds.length === 0;
    43→  const activeProject = activeProjectIds.length === 1
    44→    ? projects.find((p) => p.id === activeProjectIds[0])
    45→    : null;
    46→  const multipleSelected = activeProjectIds.length > 1;
    47→
    48→  // Get display text and color
    49→  const getDisplayInfo = () => {
    50→    if (isAllSelected) {
    51→      return {
    52→        text: 'All Projects',
    53→        color: null,
    54→        icon: <Globe className="w-4 h-4" />,
    55→      };
    56→    }
    57→    if (activeProject) {
    58→      // Show breadcrumb path if nested
    59→      const path = getProjectPath(activeProject.id);
    60→      const displayText = path.length > 1
    61→        ? path.map((p) => p.name).join(' › ')
    62→        : activeProject.name;
    63→      return {
    64→        text: displayText,
    65→        color: activeProject.color,
    66→        icon: activeProject.icon || null,
    67→      };
    68→    }
    69→    if (multipleSelected) {
    70→      return {
    71→        text: `${activeProjectIds.length} Projects`,
    72→        color: null,
    73→        icon: null,
    74→      };
    75→    }
    76→    return {
    77→      text: 'All Projects',
    78→      color: null,
    79→      icon: <Globe className="w-4 h-4" />,
    80→    };
    81→  };
    82→
    83→  const displayInfo = getDisplayInfo();
    84→
    85→  // Handle click outside
    86→  useEffect(() => {
    87→    const handleClickOutside = (event: MouseEvent) => {
    88→      if (
    89→        dropdownRef.current &&
    90→        !dropdownRef.current.contains(event.target as Node)
    91→      ) {
    92→        setIsOpen(false);
    93→      }
    94→    };
    95→
    96→    if (isOpen) {
    97→      document.addEventListener('mousedown', handleClickOutside);
    98→    }
    99→
   100→    return () => {
   101→      document.removeEventListener('mousedown', handleClickOutside);
   102→    };
   103→  }, [isOpen]);
   104→
   105→  // Handle keyboard navigation
   106→  const handleKeyDown = useCallback(
   107→    (event: React.KeyboardEvent) => {
   108→      if (event.key === 'Escape') {
   109→        setIsOpen(false);
   110→        buttonRef.current?.focus();
   111→      }
   112→    },
   113→    []
   114→  );
   115→
   116→  // Handle "All Projects" selection
   117→  const handleSelectAll = useCallback(() => {
   118→    setActiveProjects([]);
   119→    setIsOpen(false);
   120→  }, [setActiveProjects]);
   121→
   122→  // Handle project selection
   123→  const handleSelectionChange = useCallback(
   124→    (ids: string[]) => {
   125→      setActiveProjects(ids);
   126→      setIsOpen(false);
   127→    },
   128→    [setActiveProjects]
   129→  );
   130→
   131→  // Open project settings modal
   132→  const handleManageProjects = useCallback(() => {
   133→    setIsOpen(false);
   134→    setShowSettingsModal(true);
   135→  }, [setIsOpen]);
   136→
   137→  return (
   138→    <div ref={dropdownRef} className={`relative ${className}`}>
   139→      {/* Trigger Button */}
   140→      <button
   141→        ref={buttonRef}
   142→        type="button"
   143→        onClick={() => setIsOpen(!isOpen)}
   144→        onKeyDown={handleKeyDown}
   145→        className={`
   146→          flex items-center gap-2 px-3 py-1.5 rounded-lg
   147→          transition-all duration-standard ease-smooth
   148→          border border-transparent
   149→          ${isOpen
   150→            ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated border-border-light dark:border-border-dark shadow-md'
   151→            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   152→          }
   153→        `}
   154→        aria-haspopup="listbox"
   155→        aria-expanded={isOpen}
   156→        aria-label="Select project context"
   157→      >
   158→        {/* Color indicator or icon */}
   159→        {displayInfo.color ? (
   160→          <span
   161→            className="w-3 h-3 rounded-full flex-shrink-0"
   162→            style={{ backgroundColor: displayInfo.color }}
   163→          />
   164→        ) : displayInfo.icon ? (
   165→          <span className="text-text-light-secondary dark:text-text-dark-secondary">
   166→            {displayInfo.icon}
   167→          </span>
   168→        ) : (
   169→          <span className="w-3 h-3 rounded-full bg-gradient-to-r from-accent-magenta to-accent-cyan flex-shrink-0" />
   170→        )}
   171→
   172→        {/* Display text */}
   173→        <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary max-w-[200px] truncate">
   174→          {displayInfo.text}
   175→        </span>
   176→
   177→        {/* Chevron */}
   178→        <ChevronDown
   179→          className={`w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary transition-transform duration-standard ${
   180→            isOpen ? 'rotate-180' : ''
